import React, { useState } from 'react';
import api from '../../api/axios';
import { Calendar, Link as LinkIcon, Briefcase, X, Check } from 'lucide-react';
import '..candidate/css/BookingModal.css';

const BookingModal = ({ interviewer, onClose }) => {
  const [formData, setFormData] = useState({
    sessionTime: '',
    interviewType: 'DSA',
    submissionLink: ''
  });
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const requestBody = {
        interviewerId: interviewer.id,
        sessionTime: formData.sessionTime,
        interviewType: formData.interviewType,
        submissionLink: formData.submissionLink
      };

      await api.post('/v1/candidate/book', requestBody);
      setSuccess(true);
      setTimeout(() => onClose(), 2000);
    } catch (err) {
      alert("Booking failed: " + (err.response?.data?.message || "Please check your input"));
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="modal-overlay">
        <div className="modal-content success-view">
          <div className="success-icon"><Check size={48} /></div>
          <h2>Booking Confirmed!</h2>
          <p>Your session with {interviewer.firstName} has been scheduled.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="modal-overlay">
      <div className="modal-content">
        <button className="close-btn" onClick={onClose}><X size={24} /></button>

        <div className="modal-header">
          <h2>Book a Session</h2>
          <p>Interviewer: <strong>{interviewer.firstName} {interviewer.lastName}</strong></p>
        </div>

        <form onSubmit={handleSubmit}>
          {/* Slot Selection */}
          <div className="form-group">
            <label><Calendar size={18} /> Select Available Slot</label>
            <div className="slots-grid">
              {interviewer.availabilitySlots?.map((slot, index) => (
                <div key={index} className="slot-item">
                  <input
                    type="radio"
                    id={`slot-${index}`}
                    name="sessionTime"
                    value={slot}
                    onChange={(e) => setFormData({...formData, sessionTime: e.target.value})}
                    required
                  />
                  <label htmlFor={`slot-${index}`}>
                    {new Date(slot).toLocaleString([], { 
                      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' 
                    })}
                  </label>
                </div>
              ))}
            </div>
          </div>

          {/* Interview Type */}
          <div className="form-group">
            <label><Briefcase size={18} /> Interview Type</label>
            <select 
              value={formData.interviewType}
              onChange={(e) => setFormData({...formData, interviewType: e.target.value})}
            >
              <option value="DSA">Data Structures & Algorithms</option>
              <option value="System Design">System Design</option>
              <option value="Behavioral">Behavioral / HR</option>
              <option value="Full Stack">Full Stack / Frontend / Backend</option>
            </select>
          </div>

          {/* Submission Link */}
          <div className="form-group">
            <label><LinkIcon size={18} /> Resume / GitHub Link (Optional)</label>
            <input 
              type="url" 
              placeholder="https://github.com/yourprofile"
              value={formData.submissionLink}
              onChange={(e) => setFormData({...formData, submissionLink: e.target.value})}
            />
          </div>

          <div className="modal-footer">
            <span className="price-info">Total: ${interviewer.pricePerSession}</span>
            <button type="submit" className="confirm-btn" disabled={loading}>
              {loading ? "Processing..." : "Confirm Booking"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BookingModal;
